/**
 * Token-bucket rate limiter.
 */

export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number; // tokens per second
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefill);

    const newTokens = (elapsed * this.refillRate) / 1000;

    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      const combined = andFilter(...this.filters);
      result = result.filter(combined);
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  describe("basic merging", () => {
    it("merges top-level keys from source into target", () => {
      const result = deepMerge({ a: 1, b: 2 }, { b: 3, c: 4 } as any);
      expect(result).toEqual({ a: 1, b: 3, c: 4 });
    });

    it("returns a new object, not the target reference", () => {
      const target = { a: 1 };
      const result = deepMerge(target, { b: 2 } as any);
      expect(result).not.toBe(target);
      expect(target).toEqual({ a: 1 });
    });

    it("does not mutate the source object", () => {
      const source = { b: 2 };
      const target = { a: 1 };
      deepMerge(target, source as any);
      expect(source).toEqual({ b: 2 });
    });

    it("returns an equivalent but new object when source is empty", () => {
      const target = { a: 1, b: 2 };
      const result = deepMerge(target, {});
      expect(result).toEqual({ a: 1, b: 2 });
      expect(result).not.toBe(target);
    });

    it("adds new keys that only exist in source", () => {
      const result = deepMerge({ a: 1 }, { z: 99 } as any);
      expect(result).toEqual({ a: 1, z: 99 });
    });

    it("overwrites primitive with a different-typed primitive", () => {
      const result = deepMerge({ a: 1 as unknown as string }, { a: "hello" } as any);
      expect(result.a).toBe("hello");
    });

    it("overwrites boolean values", () => {
      const result = deepMerge({ a: true }, { a: false } as any);
      expect(result.a).toBe(false);
    });
  });

  describe("nested object merging", () => {
    it("merges nested objects recursively instead of replacing", () => {
      const result = deepMerge(
        { a: { x: 1, y: 2 } },
        { a: { y: 3, z: 4 } } as any
      );
      expect(result).toEqual({ a: { x: 1, y: 3, z: 4 } });
    });

    it("merges deeply nested objects at multiple levels", () => {
      const result = deepMerge(
        { a: { b: { c: { d: 1, e: 2 } } } },
        { a: { b: { c: { e: 3, f: 4 } } } } as any
      );
      expect(result).toEqual({ a: { b: { c: { d: 1, e: 3, f: 4 } } } });
    });

    it("does not share nested object references with target", () => {
      const target = { a: { x: 1 } };
      const result = deepMerge(target, { a: { y: 2 } } as any);
      expect(result.a).not.toBe(target.a);
      expect(target.a).toEqual({ x: 1 });
    });

    it("replaces object with primitive when source value is primitive", () => {
      const result = deepMerge({ a: { x: 1 } }, { a: 5 } as any);
      expect(result.a).toBe(5);
    });

    it("replaces primitive with object when target value is primitive", () => {
      const result = deepMerge({ a: 5 as unknown as object }, { a: { x: 1 } } as any);
      expect(result.a).toEqual({ x: 1 });
    });

    it("adds a nested object when target has no such key", () => {
      const result = deepMerge({ a: 1 }, { b: { x: 1 } } as any);
      expect(result).toEqual({ a: 1, b: { x: 1 } });
    });
  });

  describe("array handling (replace strategy)", () => {
    it("replaces target array entirely with source array", () => {
      const result = deepMerge({ a: [1, 2, 3] }, { a: [4, 5] } as any);
      expect(result.a).toEqual([4, 5]);
    });

    it("clones the source array rather than sharing reference", () => {
      const source = { a: [1, 2, 3] };
      const result = deepMerge({ a: [] as number[] }, source as any);
      expect(result.a).toEqual([1, 2, 3]);
      expect(result.a).not.toBe(source.a);
    });

    it("replaces an object target with an array source", () => {
      const result = deepMerge({ a: { x: 1 } }, { a: [1, 2] } as any);
      expect(result.a).toEqual([1, 2]);
    });

    it("replaces an array target with an object source", () => {
      const result = deepMerge({ a: [1, 2] as unknown as object }, { a: { x: 1 } } as any);
      expect(result.a).toEqual({ x: 1 });
    });

    it("handles empty array replacement", () => {
      const result = deepMerge({ a: [1, 2, 3] }, { a: [] } as any);
      expect(result.a).toEqual([]);
    });
  });

  describe("Date handling", () => {
    it("clones Date objects instead of sharing reference", () => {
      const date = new Date("2020-01-01T00:00:00Z");
      const result = deepMerge({ d: new Date(0) }, { d: date } as any);
      expect(result.d).not.toBe(date);
      expect((result.d as Date).getTime()).toBe(date.getTime());
    });

    it("cloned Date is a real Date instance", () => {
      const date = new Date("2021-06-15T12:00:00Z");
      const result = deepMerge({ d: null as unknown as Date }, { d: date } as any);
      expect(result.d).toBeInstanceOf(Date);
    });

    it("mutating the source Date does not affect the cloned result", () => {
      const date = new Date("2020-01-01T00:00:00Z");
      const result = deepMerge({ d: new Date(0) }, { d: date } as any);
      const cloned = result.d as Date;
      date.setFullYear(1999);
      expect(cloned.getFullYear()).toBe(2020);
    });

    it("replaces a plain object with a Date", () => {
      const date = new Date("2022-01-01T00:00:00Z");
      const result = deepMerge({ d: { x: 1 } }, { d: date } as any);
      expect(result.d).toBeInstanceOf(Date);
      expect((result.d as Date).getTime()).toBe(date.getTime());
    });
  });

  describe("null and undefined handling", () => {
    it("replaces target value with null when source is null", () => {
      const result = deepMerge({ a: 1 }, { a: null } as any);
      expect(result.a).toBeNull();
    });

    it("sets null for a key that only exists in source", () => {
      const result = deepMerge({ a: 1 }, { b: null } as any);
      expect(result).toEqual({ a: 1, b: null });
    });

    it("replaces a nested object with null", () => {
      const result = deepMerge({ a: { x: 1 } }, { a: null } as any);
      expect(result.a).toBeNull();
    });

    it("skips undefined source values and preserves target value", () => {
      const result = deepMerge({ a: 1 }, { a: undefined } as any);
      expect(result.a).toBe(1);
    });

    it("skips undefined even when target key is absent", () => {
      const result = deepMerge({ a: 1 }, { b: undefined } as any);
      expect(result).toEqual({ a: 1 });
      expect("b" in result).toBe(false);
    });

    it("preserves nested target object when source value is undefined", () => {
      const result = deepMerge({ a: { x: 1 } }, { a: undefined } as any);
      expect(result.a).toEqual({ x: 1 });
    });
  });

  describe("prototype pollution protection", () => {
    it("skips __proto__ key from source", () => {
      const malicious = JSON.parse('{"__proto__": {"polluted": true}}');
      const result = deepMerge({ a: 1 }, malicious);
      expect(({} as any).polluted).toBeUndefined();
      expect((result as any).polluted).toBeUndefined();
    });

    it("does not pollute Object.prototype via __proto__", () => {
      deepMerge({}, JSON.parse('{"__proto__": {"isAdmin": true}}'));
      expect(({} as any).isAdmin).toBeUndefined();
    });

    it("skips the constructor key", () => {
      const result = deepMerge({ a: 1 }, { constructor: "evil" } as any);
      expect(result.constructor).toBe(Object);
      expect((result as any).constructor).not.toBe("evil");
    });

    it("skips the prototype key", () => {
      const result = deepMerge({ a: 1 }, { prototype: "evil" } as any);
      expect((result as any).prototype).toBeUndefined();
    });

    it("still merges safe keys alongside forbidden ones", () => {
      const source = JSON.parse('{"__proto__": {"x": 1}, "safe": 42}');
      const result = deepMerge({ a: 1 }, source);
      expect((result as any).safe).toBe(42);
      expect((result as any).a).toBe(1);
    });
  });

  describe("symbol keys", () => {
    it("merges symbol-keyed values from source", () => {
      const sym = Symbol("s");
      const result = deepMerge({ [sym]: 1 } as any, { [sym]: 2 } as any);
      expect(result[sym]).toBe(2);
    });

    it("adds new symbol keys that only exist in source", () => {
      const sym = Symbol("new");
      const result = deepMerge({ a: 1 } as any, { [sym]: 99 } as any);
      expect((result as any)[sym]).toBe(99);
    });

    it("preserves existing symbol keys from target", () => {
      const symT = Symbol("t");
      const symS = Symbol("s");
      const result = deepMerge({ [symT]: 1 } as any, { [symS]: 2 } as any);
      expect((result as any)[symT]).toBe(1);
      expect((result as any)[symS]).toBe(2);
    });

    it("recursively merges objects under symbol keys", () => {
      const sym = Symbol("nested");
      const result = deepMerge(
        { [sym]: { x: 1 } } as any,
        { [sym]: { y: 2 } } as any
      );
      expect((result as any)[sym]).toEqual({ x: 1, y: 2 });
    });

    it("skips undefined symbol values", () => {
      const sym = Symbol("u");
      const result = deepMerge({ [sym]: 5 } as any, { [sym]: undefined } as any);
      expect((result as any)[sym]).toBe(5);
    });
  });

  describe("non-plain object handling", () => {
    it("replaces (not merges) when source is a class instance", () => {
      class Foo {
        constructor(public v: number) {}
      }
      const instance = new Foo(7);
      const result = deepMerge({ a: { v: 1 } }, { a: instance } as any);
      expect(result.a).toBe(instance);
    });

    it("replaces when target is a class instance and source is plain object", () => {
      class Foo {
        constructor(public v: number) {}
      }
      const result = deepMerge({ a: new Foo(1) as any }, { a: { w: 2 } } as any);
      expect(result.a).toEqual({ w: 2 });
    });

    it("treats object with null prototype as a plain object for merging", () => {
      const nullProto = Object.create(null);
      nullProto.x = 1;
      const result = deepMerge({ a: { y: 2 } }, { a: nullProto } as any);
      expect(result.a).toEqual({ x: 1, y: 2 });
    });
  });

  describe("miscellaneous edge cases", () => {
    it("handles number zero as a valid non-skipped value", () => {
      const result = deepMerge({ a: 5 }, { a: 0 } as any);
      expect(result.a).toBe(0);
    });

    it("handles empty string as a valid value", () => {
      const result = deepMerge({ a: "x" }, { a: "" } as any);
      expect(result.a).toBe("");
    });

    it("handles false as a valid value", () => {
      const result = deepMerge({ a: true }, { a: false } as any);
      expect(result.a).toBe(false);
    });

    it("merges multiple keys with mixed strategies at once", () => {
      const result = deepMerge(
        { keep: 1, obj: { x: 1 }, arr: [1], skipMe: 9 },
        { obj: { y: 2 }, arr: [2, 3], skipMe: undefined, nu: null } as any
      );
      expect(result).toEqual({
        keep: 1,
        obj: { x: 1, y: 2 },
        arr: [2, 3],
        skipMe: 9,
        nu: null,
      });
    });
  });
});
